DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "parserNumberWithUnits.pl", "contextForm.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context('Numeric'); $b = random(800,1000,100); $h = random(10,30,5); $k = $b - random(100,200,100); $ans = NumberWithUnits(($k - $b)/$h, 'ml/min'); $m = ($k - $b)/$h; $f = Formula("$m x + $b");
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis}[ xlabel={\(x\) (min)}, ylabel={\(y\) (mL)}, xmin=0, xmax=35, ymin=0, ymax=1100, xtick={0,5,...,30}, minor xtick=, ytick={0,100,...,1000}, minor ytick=, width=\orccaprintwidth, height=0.33\orccaprintwidth, axis line style={->}, ] \addplot+[-{Kite},domain=0:35] {$f}; \end{axis} \end{tikzpicture}
END_LATEX_IMAGE
############################################################ # Body ############################################################
BEGIN_PGML A liquid solution is slowly leaking from a container. This graph shows how many milliliters [`y`] of solution remains in the container after [`x`] minutes.
>> [@image(insertGraph($image_1), width=>450)@]* <<
What is the slope of this line, including units?
[_]{$ans}{16}
END_PGML
